# Remove old sessions periodically
import os
from datetime import datetime, timedelta

def prune_old_memories(days=30):
    cutoff = datetime.now() - timedelta(days=days)
    for file in os.listdir("/memory/summaries"):
        file_path = f"/memory/summaries/{file}"
        if os.path.getmtime(file_path) < cutoff.timestamp():
            os.remove(file_path)

def safe_memory_operation(command, path, content=None):
    try:
        if command == "create":
            with open(path, "w") as f:
                f.write(content)
        elif command == "read":
            return open(path).read()
        return {"success": True, "message": f"Operation {command} completed"}
    except Exception as e:
        return {"success": False, "error": str(e)}

def validate_path(path):
    if not path.startswith("/memory/"):
        raise ValueError("Path must be in /memory directory")
    if ".." in path:
        raise ValueError("Directory traversal detected")
